import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { motion } from 'framer-motion';

const Quiz = () => {
  const [questions, setQuestions] = useState([]);
  const [step, setStep] = useState(0);
  const [choice, setChoice] = useState(null);
  const [status, setStatus] = useState('idle'); // 'idle', 'correct', 'wrong'

  useEffect(() => {
    // On charge les questions via ton backend
    axios.get('http://localhost:8000/questions/random?limit=30')
      .then(res => setQuestions(res.data));
  }, []);

  const handleCheck = () => {
    if (choice === questions[step].solution) setStatus('correct');
    else setStatus('wrong');
  };

  const handleNext = () => {
    setChoice(null);
    setStatus('idle');
    setStep(s => s + 1);
  };

  if (!questions.length) return <p className="text-center font-bold">Initialisation de la base...</p>;
  if (step >= questions.length) return <div className="text-center bg-white p-10 rounded-3xl shadow-lg border-2 border-slate-200">🏆 Score Final : {questions.length}/{questions.length} !</div>;

  const q = questions[step];

  return (
    <div className="flex flex-col gap-8">
      {/* Barre de progression */}
      <div className="w-full bg-slate-200 h-4 rounded-full overflow-hidden">
        <div className="bg-green-500 h-full transition-all duration-500" style={{ width: `${(step / questions.length) * 100}%` }} />
      </div>

      <div className="bg-white p-8 rounded-3xl border-2 border-slate-200 shadow-sm">
        <span className="text-xs font-bold text-blue-500 uppercase tracking-widest">{q.difficulte}</span>
        <h2 className="text-2xl font-bold mt-2 mb-8">{q.enonce}</h2>

        <div className="grid gap-3">
          {q.propositions.map((p, i) => (
            <button
              key={i}
              disabled={status !== 'idle'}
              onClick={() => setChoice(p)}
              className={`p-4 rounded-2xl border-2 font-mono text-sm text-left transition-all ${
                choice === p ? 'border-blue-400 bg-blue-50' : 'border-slate-100 hover:bg-slate-50'
              } ${status !== 'idle' && p === q.solution ? 'border-green-500 bg-green-50' : ''}`}
            >
              {p}
            </button>
          ))}
        </div>
      </div>

      {/* Zone de Feedback (Style Duolingo en bas) */}
      <div className={`p-6 rounded-2xl flex items-center justify-between transition-colors ${
        status === 'idle' ? 'bg-white' : status === 'correct' ? 'bg-green-100' : 'bg-red-100'
      }`}>
        <div className="flex-1">
          {status !== 'idle' && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
              <h3 className={`font-black text-xl ${status === 'correct' ? 'text-green-700' : 'text-red-700'}`}>
                {status === 'correct' ? 'Excellent !' : 'La réponse était :'}
              </h3>
              <p className="text-slate-700 mt-1 italic">{q.explication}</p>
            </motion.div>
          )}
        </div>
        
        {status === 'idle' ? (
          <button onClick={handleCheck} disabled={!choice} className="bg-green-500 text-white px-10 py-3 rounded-2xl font-black shadow-[0_4px_0_0_#22c55e] hover:brightness-110 disabled:grayscale">
            VÉRIFIER
          </button>
        ) : (
          <button onClick={handleNext} className="bg-blue-500 text-white px-10 py-3 rounded-2xl font-black shadow-[0_4px_0_0_#3b82f6] hover:brightness-110">
            CONTINUER
          </button>
        )}
      </div>
    </div>
  );
};

export default Quiz;
